import sys

def read_sheet(h, w):
    return [input().strip() for _ in range(h)]

def main():
    # Read input
    ha, wa = map(int, sys.stdin.readline().split())
    a = read_sheet(ha, wa)
    hb, wb = map(int, sys.stdin.readline().split())
    b = read_sheet(hb, wb)
    hx, wx = map(int, sys.stdin.readline().split())
    x = read_sheet(hx, wx)

    # Collect all black positions in A and B
    blacks_a = [(i, j) for i in range(ha) for j in range(wa) if a[i][j] == '#']
    blacks_b = [(i, j) for i in range(hb) for j in range(wb) if b[i][j] == '#']

    # For each possible position of A and B, simulate the black squares on C
    for dx_a in range(-10, 10):
        for dy_a in range(-10, 10):
            # Positions of black squares from A
            pos_a = set()
            for i, j in blacks_a:
                pos_a.add((i + dx_a, j + dy_a))

            for dx_b in range(-10, 10):
                for dy_b in range(-10, 10):
                    # Positions of black squares from B
                    pos_b = set()
                    for i, j in blacks_b:
                        pos_b.add((i + dx_b, j + dy_b))

                    # Combine positions of A and B
                    combined = pos_a.union(pos_b)

                    # Check if all black squares are within the cut-out region
                    # Try all possible cut-out regions of size hx x wx
                    for cut_top in range(-10, 10):
                        for cut_left in range(-10, 10):
                            # Check if all black squares are in the cut-out region
                            valid = True
                            for (i, j) in combined:
                                if not (cut_top <= i < cut_top + hx and cut_left <= j < cut_left + wx):
                                    valid = False
                                    break
                            if not valid:
                                continue

                            # Now check if the cut-out region matches X
                            match = True
                            for i in range(hx):
                                for j in range(wx):
                                    # Position on C
                                    c_i = cut_top + i
                                    c_j = cut_left + j
                                    # Check if it's black
                                    is_black = (c_i, c_j) in combined
                                    if x[i][j] == '#' and not is_black:
                                        match = False
                                        break
                                if not match:
                                    break
                            if match:
                                print("Yes")
                                return

    print("No")

if __name__ == "__main__":
    main()
